package bead

import (
	"crypto/sha1"
	"encoding/hex"
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"time"
)

const claimLivenessNamespace = "ddx-claim-heartbeats"

type claimLivenessRecord struct {
	BeadID    string    `json:"bead_id"`
	UpdatedAt time.Time `json:"updated_at"`
	PID       int       `json:"pid,omitempty"`
}

func claimLivenessPath(ddxDir, id string) string {
	root := canonicalClaimRoot(ddxDir)
	sum := sha1.Sum([]byte(root))
	return filepath.Join(os.TempDir(), claimLivenessNamespace, hex.EncodeToString(sum[:]), id+".json")
}

func canonicalClaimRoot(ddxDir string) string {
	root := filepath.Clean(filepath.Dir(ddxDir))
	if abs, err := filepath.Abs(root); err == nil {
		root = abs
	}
	if real, err := filepath.EvalSymlinks(root); err == nil {
		root = real
	}
	return filepath.Clean(root)
}

func writeAtomicClaimFile(path string, data []byte) error {
	dir := filepath.Dir(path)
	if err := os.MkdirAll(dir, 0o755); err != nil {
		return fmt.Errorf("bead: mkdir claim liveness dir: %w", err)
	}
	tmp, err := os.CreateTemp(dir, filepath.Base(path)+".tmp-*")
	if err != nil {
		return fmt.Errorf("bead: create claim liveness tmp: %w", err)
	}
	tmpName := tmp.Name()
	defer func() {
		_ = tmp.Close()
		_ = os.Remove(tmpName)
	}()
	if _, err := tmp.Write(data); err != nil {
		return fmt.Errorf("bead: write claim liveness tmp: %w", err)
	}
	if err := tmp.Close(); err != nil {
		return fmt.Errorf("bead: close claim liveness tmp: %w", err)
	}
	if err := os.Rename(tmpName, path); err != nil {
		return fmt.Errorf("bead: publish claim liveness: %w", err)
	}
	return nil
}

func (s *Store) TouchClaimHeartbeat(id string) error {
	rec := claimLivenessRecord{
		BeadID:    id,
		UpdatedAt: time.Now().UTC(),
		PID:       os.Getpid(),
	}
	data, err := json.Marshal(rec)
	if err != nil {
		return fmt.Errorf("bead: marshal claim liveness: %w", err)
	}
	data = append(data, '\n')
	return writeAtomicClaimFile(claimLivenessPath(s.Dir, id), data)
}

func (s *Store) RemoveClaimHeartbeat(id string) error {
	err := os.Remove(claimLivenessPath(s.Dir, id))
	if err == nil || os.IsNotExist(err) {
		return nil
	}
	return fmt.Errorf("bead: remove claim liveness: %w", err)
}

func (s *Store) ClaimHeartbeatFresh(id string) (bool, bool, error) {
	data, err := os.ReadFile(claimLivenessPath(s.Dir, id))
	if os.IsNotExist(err) {
		return false, false, nil
	}
	if err != nil {
		return false, false, fmt.Errorf("bead: read claim liveness: %w", err)
	}
	var rec claimLivenessRecord
	if err := json.Unmarshal(data, &rec); err != nil {
		return false, true, fmt.Errorf("bead: parse claim liveness: %w", err)
	}
	if rec.UpdatedAt.IsZero() {
		return false, true, nil
	}
	return time.Since(rec.UpdatedAt) <= HeartbeatTTL, true, nil
}

---
// Package bead implements the on-disk bead tracker.
//
// Size envelope (ddx-f8a11202):
//
// Individual bead fields — description, acceptance, notes, and each event's
// body — are bounded by MaxFieldBytes (65,535 bytes). This matches upstream
// bd's Dolt TEXT column limit so DDx-authored beads can always round-trip
// through `bd import`. Writers exceeding the cap are truncated with a
// `…[truncated, N bytes]` marker at AppendEvent; callers that need to
// preserve the full payload (notably reviewer streams) should persist to a
// sidecar artifact under `.ddx/executions/<id>/` and record a path
// reference in the event body.
//
// On the read side, scanners use a 16MB buffer — real-world incidents have
// produced 1.46MB bead rows and ~7MB session-log rows when writers bypassed
// the cap. 16MB comfortably fits a bead with dozens of maxed-out fields and
// matches the scanner in the agent package.
package bead

import (
	"bufio"
	"bytes"
	"context"
	"crypto/rand"
	"encoding/hex"
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"sort"
	"strconv"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/config"
	gitpkg "github.com/DocumentDrivenDX/ddx/internal/git"
)

// Store manages beads via a pluggable backend.
type Store struct {
	Collection string
	Dir        string
	File       string
	Prefix     string
	LockDir    string
	LockWait   time.Duration
	backend    RawBackend // nil means use built-in JSONL
}

// Compile-time check: *Store satisfies the high-level Backend interface
// declared in backend.go. This is the contract chaos_test.go and (eventually)
// cli/cmd callers program against.
var _ Backend = (*Store)(nil)

type StoreOption func(*Store)

// WithCollection selects the logical bead collection. The default collection
// remains "beads", which maps to "beads.jsonl" in the JSONL backend.
func WithCollection(name string) StoreOption {
	return func(s *Store) {
		if cleaned := normalizeCollection(name); cleaned != "" {
			s.Collection = cleaned
		}
	}
}

// NewStore creates a store with the given directory.
// Defaults can be overridden via options or environment.
func NewStore(dir string, opts ...StoreOption) *Store {
	if dir == "" {
		dir = envOr("DDX_BEAD_DIR", ".ddx")
	}
	workingDir := dir
	if filepath.Base(dir) == ".ddx" {
		workingDir = filepath.Dir(dir)
	}
	prefix := envOr("DDX_BEAD_PREFIX", "")
	var configBackend string
	if cfg, err := config.LoadWithWorkingDir(workingDir); err == nil && cfg != nil && cfg.Bead != nil {
		if prefix == "" && cfg.Bead.IDPrefix != "" {
			prefix = cfg.Bead.IDPrefix
		}
		configBackend = cfg.Bead.Backend
	}
	if prefix == "" {
		prefix = detectPrefix(workingDir)
	}
	// Backend selection: env var wins, then config, then jsonl default.
	backendType := os.Getenv("DDX_BEAD_BACKEND")
	if backendType == "" {
		backendType = configBackend
	}
	if backendType == "" {
		backendType = BackendJSONL
	}

	s := &Store{
		Collection: DefaultCollection,
		Dir:        dir,
		Prefix:     prefix,
		LockWait:   parseDurationOr("DDX_BEAD_LOCK_TIMEOUT", 10*time.Second),
	}
	for _, opt := range opts {
		if opt != nil {
			opt(s)
		}
	}
	spec := DefaultRegistry().Resolve(CollectionID(s.Collection))
	s.File, s.LockDir = spec.PathsUnder(dir)

	// Set up external backend if configured. bd/br lack per-collection
	// scoping in their CLI, so non-default collections (e.g. beads-archive)
	// route through a JSONL fallback the external backend transparently
	// delegates to. The default collection always goes straight to bd/br
	// to preserve the existing interchange contract (schema_compat_test.go,
	// import/export round-trip).
	switch backendType {
	case BackendBD, BackendBR:
		var fallback RawBackend
		if s.Collection != DefaultCollection {
			fallback = NewJSONLBackend(s.Dir, s.File, s.LockDir, s.LockWait)
		}
		if ext, err := NewExternalBackendWithFallback(backendType, s.Collection, fallback); err == nil {
			s.backend = ext
		}
		// Fall through to JSONL if tool not available
	case BackendAxon:
		s.backend = NewAxonBackend(s.Dir, s.LockWait)
	}

	return s
}

// NewStoreWithCollection creates a store for a named logical collection.
func NewStoreWithCollection(dir, collection string) *Store {
	return NewStore(dir, WithCollection(collection))
}

// Init creates the storage directory and file.
func (s *Store) Init() error {
	if s.backend != nil {
		return s.backend.Init()
	}
	if err := os.MkdirAll(s.Dir, 0o755); err != nil {
		return fmt.Errorf("bead: init dir: %w", err)
	}
	f, err := os.OpenFile(s.File, os.O_CREATE|os.O_WRONLY, 0o644)
	if err != nil {
		return fmt.Errorf("bead: init file: %w", err)
	}
	return f.Close()
}

// GenID generates a unique bead ID with the configured prefix.
func (s *Store) GenID() (string, error) {
	b := make([]byte, 4)
	if _, err := rand.Read(b); err != nil {
		return "", fmt.Errorf("bead: gen id: %w", err)
	}
	return fmt.Sprintf("%s-%s", s.Prefix, hex.EncodeToString(b)), nil
}

// ReadAll loads all beads from the configured backend.
func (s *Store) ReadAll() ([]Bead, error) {
	return s.ReadAllFiltered(nil)
}

// ReadAllFiltered loads all beads, folds them by latest-wins, and returns only
// those for which the predicate returns true. When the predicate is nil every
// bead is returned (equivalent to ReadAll). The predicate is applied at the
// per-entry parse boundary after fold — matched beads are appended directly to
// the return slice without first being held in an intermediate full-corpus
// list, so queries that match a small subset avoid materializing the
// mismatches (ddx-9ce6842a Part 2 step 2: filter pushdown).
func (s *Store) ReadAllFiltered(pred func(Bead) bool) ([]Bead, error) {
	if s.backend != nil {
		all, err := s.backend.ReadAll()
		if err != nil {
			return nil, err
		}
		if pred == nil {
			return all, nil
		}
		out := make([]Bead, 0, len(all))
		for _, b := range all {
			if pred(b) {
				out = append(out, b)
			}
		}
		return out, nil
	}
	beads, warnings, err := s.readAllRaw()
	if err != nil {
		return nil, fmt.Errorf("bead: read %s: %w", s.File, err)
	}
	beads = foldLatestBeads(beads)
	for _, warning := range warnings {
		fmt.Fprintln(os.Stderr, warning)
	}
	if len(warnings) > 0 && len(beads) > 0 {
		repaired, repairErr := s.repairJSONL()
		if repairErr != nil {
			return beads, fmt.Errorf("bead: repair %s: %w", s.File, repairErr)
		}
		if repaired {
			fmt.Fprintf(os.Stderr, "bead: repaired %s; backup written to %s.bak\n", s.File, s.File)
		}
	}
	if len(beads) == 0 && len(warnings) > 0 {
		return nil, fmt.Errorf("bead: read %s: %d malformed record(s), 0 valid", s.File, len(warnings))
	}
	if pred == nil {
		return beads, nil
	}
	out := make([]Bead, 0, len(beads))
	for _, b := range beads {
		if pred(b) {
			out = append(out, b)
		}
	}

		res.ExitCode = 0
		res.FailureMode = ""
		res.Status = ExecuteBeadStatusPreservedNeedsReview
		res.Detail = ExecuteBeadStatusDetail(res.Status, OperatorCancelReason, "")
		_ = writeArtifactJSON(artifacts.ResultAbs, res)
		return res, nil
	}

	// Classify failure mode from worker-level signals. ApplyLandingToResult
	// may refine this with landing-level signals (merge conflict, gate
	// failure) before the final result is output.
	res.FailureMode = ClassifyFailureMode(res.Outcome, res.ExitCode, res.Error)

	// Record routing evidence on the bead (best-effort; errors are discarded).
	// Include requested passthrough constraints and power bounds so analytics
	// can separate intent from resolved outcome (AC5 of ddx-20047dd5).
	appendBeadRoutingEvidence(runtime.BeadEvents, beadID, resultHarness, resultProvider, resultModel, routeReason, routeBaseURL, rcfg.Passthrough(), rcfg.MinPower(), rcfg.MaxPower(), actualPower)

	// Record per-attempt cost evidence so cost rollup never has to join
	// against the session index. Best-effort; errors are discarded.
	appendBeadCostEvidence(runtime.BeadEvents, beadID, attemptID, costEventBody{
		Harness:      resultHarness,
		Provider:     resultProvider,
		Model:        resultModel,
		InputTokens:  inputTokens,
		OutputTokens: outputTokens,
		TotalTokens:  tokens,
		CostUSD:      costUSD,
		DurationMS:   res.DurationMS,
		ExitCode:     exitCode,
	})

	populateWorkerStatus(res)
	if err := writeArtifactJSON(artifacts.ResultAbs, res); err != nil {
		return nil, fmt.Errorf("writing execute-bead result artifact: %w", err)
	}

	// Optional out-of-band mirror of the bundle. Wired here so the whole
	// per-attempt directory (manifest, prompt, result, usage, checks,
	// embedded/) is on disk before the upload starts. Failures never affect
	// the bead outcome — see executions_mirror.go.
	MirrorOrLog(MirrorRequest{
		ProjectRoot: projectRoot,
		AttemptID:   attemptID,
		BeadID:      beadID,
		BundleDir:   artifacts.DirAbs,
		Cfg:         rcfg.MirrorConfig(),
	})

	return res, nil
}

// dispatchAgentRun is a thin SD-024 wrapper around dispatchViaResolvedConfig
// for the execute-bead worker. It threads the durable knobs from rcfg and the
// per-invocation plumbing from runtime through the shared dispatch seam in
// service_run.go.
//
// The script and virtual harnesses are DDx-side helpers that the agent service
// does not implement; the underlying RunViaServiceWith path delegates those to
// a private Runner internally, so they continue to work through this path.
func dispatchAgentRun(ctx context.Context, projectRoot string, svc agentlib.FizeauService, runner AgentRunner, rcfg config.ResolvedConfig, runtime AgentRunRuntime) (*Result, error) {
	return dispatchViaResolvedConfig(ctx, projectRoot, svc, runner, rcfg, runtime)
}

// populateWorkerStatus fills in the Status and Detail fields on a worker result
// based on the task-level Outcome.
func populateWorkerStatus(res *ExecuteBeadResult) {
	switch res.Outcome {
	case ExecuteBeadOutcomeTaskSucceeded:
		res.Status = ExecuteBeadStatusSuccess
	case ExecuteBeadOutcomeTaskNoChanges:
		res.Status = ExecuteBeadStatusNoChanges
	case ExecuteBeadOutcomeTaskNoEvidence:
		res.Status = ExecuteBeadStatusNoEvidenceProduced
	default:
		res.Status = ExecuteBeadStatusExecutionFailed
	}
	res.Detail = ExecuteBeadStatusDetail(res.Status, "", res.Error)
}

// CommitTracker commits beads.jsonl if it has uncommitted changes.
func CommitTracker(projectRoot string) error {
	trackerFile := filepath.Join(projectRoot, ".ddx", "beads.jsonl")
	info, err := os.Stat(trackerFile)
	if err != nil {
		if os.IsNotExist(err) {
			return nil
		}
		return fmt.Errorf("checking tracker file: %w", err)
	}
	if info.IsDir() {
		return nil
	}

	out, err := internalgit.Command(context.Background(), projectRoot, "rev-parse", "--is-inside-work-tree").Output()
	if err != nil || strings.TrimSpace(string(out)) != "true" {
		return nil
	}

	msg := fmt.Sprintf("chore: update tracker (execute-bead %s)", time.Now().UTC().Format("20060102T150405"))
	// Serialize git add/commit on the primary .git across processes so that
	// concurrent workers (multiple `ddx work`) do not race on
	// .git/index.lock. See cli/internal/agent/tracker_lock.go.
	return withTrackerLock(projectRoot, func() error {
		// Re-check inside the lock: a sibling worker may have already
		// committed the tracker changes between our pre-lock check and now.

---
		// committed the tracker changes between our pre-lock check and now.
		diff, err := internalgit.Command(context.Background(), projectRoot, "diff", "--", ".ddx/beads.jsonl").Output()
		if err != nil {
			return fmt.Errorf("checking tracker diff: %w", err)
		}
		if strings.TrimSpace(string(diff)) == "" {
			untracked, err := internalgit.Command(context.Background(), projectRoot, "ls-files", "--others", "--exclude-standard", ".ddx/beads.jsonl").Output()
			if err != nil {
				return fmt.Errorf("checking tracker untracked: %w", err)
			}
			if strings.TrimSpace(string(untracked)) == "" {
				return nil
			}
		}

		commitOut, err := internalgit.Command(context.Background(), projectRoot, "add", ".ddx/beads.jsonl").CombinedOutput()
		if err != nil {
			return fmt.Errorf("staging tracker: %s: %w", strings.TrimSpace(string(commitOut)), err)
		}
		// `git commit` would fail with "nothing to commit" if the file's
		// content is byte-identical to HEAD even though `git diff` saw a
		// diff (e.g. mode/whitespace race). Bail cleanly in that case.
		if cached, err := internalgit.Command(context.Background(), projectRoot, "diff", "--cached", "--", ".ddx/beads.jsonl").Output(); err == nil && strings.TrimSpace(string(cached)) == "" {
			return nil
		}
		commitOut, err = internalgit.Command(context.Background(), projectRoot, "commit", "--no-verify", "-m", msg).CombinedOutput()
		if err != nil {
			return fmt.Errorf("committing tracker: %s: %w", strings.TrimSpace(string(commitOut)), err)
		}
		return nil
	})
}

func resolveBase(gitOps GitOps, workDir, fromRev string) (string, error) {
	if fromRev == "" || fromRev == "HEAD" {
		rev, err := gitOps.HeadRev(workDir)
		if err != nil {
			return "", fmt.Errorf("resolving HEAD: %w", err)
		}
		return rev, nil
	}
	rev, err := gitOps.ResolveRev(workDir, fromRev)
	if err != nil {
		return "", fmt.Errorf("resolving --from %q: %w", fromRev, err)
	}
	return rev, nil
}

